kernel void findK(
    long maxheight,
    const global knode *knodes,
    long knodes_elem,
    const global record *records,
    global long *currKnode,
    global long *offset,
    global const int *keys,
    global record *ans)
{
    int bid = get_group_id(0);
    int thid = get_local_id(0);
    int order = DEFAULT_ORDER;
    int threadsPerBlock = (order < 1024) ? order : 1024;

    if (bid >= get_num_groups(0)) return;
    if (thid >= threadsPerBlock) return;

    long current_offset = offset[bid];
    long current_knode = currKnode[bid];
    int key_val = keys[bid];

    for (int i = 0; i < maxheight; i++) {
        if (thid < threadsPerBlock) {
            if (key_val >= knodes[current_knode].keys[thid] && key_val < knodes[current_knode].keys[thid + 1]) {
                if (knodes_elem > knodes[current_offset].indices[thid]) {
                    current_offset = knodes[current_offset].indices[thid];
                }
            }
        }
        if (thid == 0) {
            currKnode[bid] = current_offset;
            current_knode = current_offset;
        }
    }

    if (thid < threadsPerBlock) {
        if (key_val == knodes[current_knode].keys[thid]) {
            ans[bid].value = records[knodes[current_knode].indices[thid]].value;
        }
    }
}

