    if (thid >= threadsPerBlock) return;

    long current_offset = offset[bid];
    long current_knode = currKnode[bid];
    long last_offset = offset_2[bid];
    long last_knode = lastKnode[bid];
    int start_val = start[bid];
    int end_val = end[bid];

    for (int i = 0; i < maxheight; i++) {
        if (thid < threadsPerBlock) {
            if ((start_val >= knodes[current_knode].keys[thid]) && (start_val < knodes[current_knode].keys[thid + 1])) {
                if (knodes_elem > knodes[current_knode].indices[thid]) {
                    current_offset = knodes[current_knode].indices[thid];
                }
            }
            if ((end_val >= knodes[last_knode].keys[thid]) && (end_val < knodes[last_knode].keys[thid + 1])) {
                if (knodes_elem > knodes[last_knode].indices[thid]) {
                    last_offset = knodes[last_knode].indices[thid];
                }
